      // Find what destinations each value maps to.
      BasicBlock *DestNeg1 = nullptr;
      BasicBlock *Dest0 = nullptr;
      BasicBlock *DestPos1 = nullptr;
      BasicBlock *DefaultDest = SI->getDefaultDest();

      for (auto Case : SI->cases()) {
        int64_t V = Case.getCaseValue()->getSExtValue();
        if (V == -1) DestNeg1 = Case.getCaseSuccessor();
        else if (V == 0) Dest0 = Case.getCaseSuccessor();
        else if (V == 1) DestPos1 = Case.getCaseSuccessor();
      }

      if (!DestNeg1) DestNeg1 = DefaultDest;
      if (!Dest0) Dest0 = DefaultDest;
      if (!DestPos1) DestPos1 = DefaultDest;

