      BasicBlock *TrueDest = nullptr;
      BasicBlock *FalseDest = nullptr;
      ICmpInst::Predicate Pred;

      bool IsUCmp = CB->getIntrinsicID() == Intrinsic::ucmp;

      if (Dest0 == DestPos1 && DestNeg1 != Dest0) {
        // -1 goes one way, 0 and 1 go another -> a < b
        Pred = IsUCmp ? ICmpInst::ICMP_ULT : ICmpInst::ICMP_SLT;
        TrueDest = DestNeg1;
        FalseDest = Dest0;
      } else if (DestNeg1 == Dest0 && DestPos1 != Dest0) {
        // -1 and 0 go one way, 1 goes another -> a > b
        Pred = IsUCmp ? ICmpInst::ICMP_UGT : ICmpInst::ICMP_SGT;
        TrueDest = DestPos1;
        FalseDest = Dest0;
      } else if (DestNeg1 == DestPos1 && Dest0 != DestNeg1) {
        // -1 and 1 go one way, 0 goes another -> a != b
        Pred = ICmpInst::ICMP_NE;
        TrueDest = DestNeg1;
        FalseDest = Dest0;
      }

